function solve(grid: number[][], k: number): number {
    let count = 0;
    const m = grid.length;
    const n = grid[0].length;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] > 0) {
                const queue: [number, number][] = [[i, j]];
                grid[i][j] = 0;
                let originalValue = grid[i][j];
                let sum = originalValue;
                while (queue.length > 0) {
                    const [x, y] = queue.shift()!;
                    for (const [dx, dy] of [[-1, 0], [1, 0], [0, -1], [0, 1]]) {
                        const nx = x + dx;
                        const ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                            originalValue = grid[nx][ny];
                            sum += originalValue;
                            grid[nx][ny] = 0;
                            queue.push([nx, ny]);
                        }
                    }
                }
                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}

